sql:
SELECT name, cp
FROM pokemon_species
ORDER BY cp DESC;

external_knowledge:
Pokémon generations refer to the different generations of Pokémon games, with the first generation including Pokémon from the Kanto region (e.g., Bulbasaur, Charmander) and the second generation including Pokémon from the Johto region (e.g., Chikorita, Cyndaquil).
; 
Pokémon encounters refer to instances where a trainer has encountered a wild Pokémon or another trainer's Pokémon in a battle.
; 
Pokémon ratings refer to the ratings given to a Pokémon based on its performance in battles.

sql:
SELECT AVG(rating_value) AS average_rating
FROM pokemon_ratings
WHERE pokemon_id = 1;

SELECT COUNT(encounter_id) AS total_encounters
FROM pokemon_encounters
WHERE user_id = 1;

SELECT capture_success, COUNT(*) AS encounter_count
FROM pokemon_encounters
GROUP BY capture_success;

SELECT ps.primary_type AS primary_type, AVG(ps.spawn_chance) AS average_spawn_chance
FROM pokemon_species ps
GROUP BY ps.primary_type;

SELECT pokemon_id
FROM pokemon_battles
WHERE outcome = 'win';

SELECT name
FROM pokemon_species
WHERE pokemon_id = 1;
